class ETGSalesInvoiceCocoaController extends SrsReportRunController
{
    CustInvoiceJour             CustInvoiceJour;

}

Method.Source:
protected void prePromptModifyContract()
{
    ETGSalesInvoiceCocoaContract         salesTaxInvoice;

    custInvoiceJour =    this.parmArgs().record();
    salesTaxInvoice   = this.parmReportContract().parmRdpContract() as ETGSalesInvoiceCocoaContract;
   // salesTaxInvoice = this.parmReportContract().parmRdlContract().parmLanguageId('fr-FR') as salesTaxInvoice;
   // this.parmReportContract().parmRdlCOntract().parmLanguageId('fr-FR');
    salesTaxInvoice.parmRecid(custInvoiceJour.RecId);
}

public static ETGSalesInvoiceCocoaController construct()
{
    return new ETGSalesInvoiceCocoaController();
}

public static void main(Args _args)
{
    ETGSalesInvoiceCocoaController salesTaxInvoice  = new ETGSalesInvoiceCocoaController();
    salesTaxInvoice.parmArgs(_args);
    salesTaxInvoice.parmReportName(ssrsReportStr(ETGSalesInvoiceCocoa, ETGSalesInvoiceCocoa));
    salesTaxInvoice.parmShowDialog(false);
    salesTaxInvoice.startOperation();
}
